// src/components/ResultView.js
import React from "react";
import Quiz from "./Quiz";

export default function ResultView({ data }) {
  const { text, quiz } = data;

  return (
    <div style={{ marginTop: "30px" }}>

      <div style={{
        background: "#f1f5f9",
        borderRadius: "10px",
        padding: "20px",
        border: "1px solid #cbd5e1",
        marginBottom: "25px"
      }}>
        <h2 style={{ color: "#1e40af" }}>Extracted Text</h2>
        <pre style={{
          whiteSpace: "pre-wrap",
          background: "white",
          padding: "15px",
          borderRadius: "8px",
          border: "1px solid #d1d5db"
        }}>
          {text}
        </pre>
      </div>

      <Quiz items={quiz || []} extractedText={text} />
    </div>
  );
}
